        for arg in &self.extra_args {
            command.arg(arg);
        }

        command
            .arg("exec")
            .arg("--skip-git-repo-check")
            .arg("--ephemeral")
            .arg("-o")
            .arg(&output_path)
            .arg(prompt);

        let output = tokio::time::timeout(self.timeout, command.output())
            .await
            .map_err(|_| ProviderError::Unavailable { status: 504 })?
            .map_err(|e| ProviderError::Parse(e.to_string()))?;

