use std::path::PathBuf;

use clap::{Parser, Subcommand};
use clap_complete::Shell;

#[derive(Parser)]
#[command(name = "omega", about = "Ω sovereign CLI", version)]
pub struct Cli {
    #[command(subcommand)]
    pub command: Option<Command>,
}

#[derive(Subcommand)]
pub enum Command {
    /// Route to best available agent
    Ask {
        #[arg(trailing_var_arg = true)]
        prompt: Vec<String>,
        #[arg(long, default_value = "omega")]
        mode: String,
    },
    /// Route directly to Claude
    AskClaude {
        #[arg(trailing_var_arg = true)]
        prompt: Vec<String>,
    },
    /// Route directly to 
    Ask {
        #[arg(trailing_var_arg = true)]
        prompt: Vec<String>,
    },
    /// Activity summary
    Briefing,
    /// Full local + live diagnostics panel
    Inspect,
    /// CPU/RAM vitals
    Pulse,
    /// Show linked provider availability
    Providers,
    /// Browse and replay saved chat history
    History {
        #[arg(long)]
        search: Option<String>,
        #[arg(long)]
        replay: Option<String>,
        #[arg(long, default_value_t = 10)]
        limit: usize,
    },
    /// Interactive multi-agent chat
    Chat {
        #[arg(short, long)]
        workspace: Option<PathBuf>,
    },
    /// Forward task to another agent
    Forward {
        #[arg(trailing_var_arg = true)]
        prompt: Vec<String>,
    },
    /// Show collective accomplishments
    Gains,
    /// Performance mode control
    Warp {
        #[command(subcommand)]
        action: WarpAction,
    },
    /// Generate shell completion scripts
    Completions {
        #[arg(value_enum)]
        shell: Shell,
    },
    /// Show or link local CLI configuration
    Config {
        #[command(subcommand)]
        action: ConfigAction,
    },
}

#[derive(Subcommand)]
pub enum WarpAction {
    /// Enable performance mode (stop non-essential services)
    Engage,
    /// Restore services
    Disengage,
}

#[derive(Subcommand)]
pub enum ConfigAction {
    /// Show the resolved CLI configuration
    Show,
    /// Save the gateway link locally and verify connectivity
    Link {
        #[arg(long)]
        gateway_url: String,
        #[arg(long)]
        token: Option<String>,
        #[arg(long)]
        mode: Option<String>,
        #[arg(long)]
        temperature: Option<f32>,
        #[arg(long)]
        timeout_secs: Option<u64>,
    },
    /// Verify the current link and gateway health
    Doctor,
}
